package library

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
)

func TestSetCoverURLPreservesUnknownKeys(t *testing.T) {
	dir := t.TempDir()
	initial := map[string]any{
		"comment":      "Generated by Mango. DO NOT EDIT!",
		"progress":     map[string]any{"user1": map[string]any{"e1": float64(3)}},
		"display_name": "My Book",
		"cover_url":    "",
	}
	if err := SaveTitleInfoMap(dir, initial); err != nil {
		t.Fatal(err)
	}

	title := &Title{Dir: dir}
	if err := title.SetCoverURL("/uploads/img/abc.png"); err != nil {
		t.Fatal(err)
	}

	raw, err := os.ReadFile(filepath.Join(dir, "info.json"))
	if err != nil {
		t.Fatal(err)
	}
	var m map[string]any
	if err := json.Unmarshal(raw, &m); err != nil {
		t.Fatal(err)
	}
	if m["cover_url"] != "/uploads/img/abc.png" {
		t.Fatalf("cover_url = %v", m["cover_url"])
	}
	if m["display_name"] != "My Book" {
		t.Fatalf("display_name lost: %v", m["display_name"])
	}
	if _, ok := m["progress"]; !ok {
		t.Fatal("progress key lost")
	}
}

func TestSetEntryCoverURL(t *testing.T) {
	dir := t.TempDir()
	title := &Title{Dir: dir}
	if err := title.SetEntryCoverURL("Chapter 1", "/uploads/img/c1.png"); err != nil {
		t.Fatal(err)
	}
	m, err := LoadTitleInfoMap(dir)
	if err != nil {
		t.Fatal(err)
	}
	em, ok := m["entry_cover_url"].(map[string]any)
	if !ok {
		t.Fatalf("entry_cover_url type %T", m["entry_cover_url"])
	}
	if em["Chapter 1"] != "/uploads/img/c1.png" {
		t.Fatalf("got %v", em["Chapter 1"])
	}
}

func TestLoadMissingInfoJSON(t *testing.T) {
	dir := t.TempDir()
	m, err := LoadTitleInfoMap(dir)
	if err != nil {
		t.Fatal(err)
	}
	if len(m) != 0 {
		t.Fatalf("expected empty map, got %v", m)
	}
}
